/**
 * @generated by @flusk/cli — cli-command recipe
 * CLI command: flusk alerts-mute
 */
import { Command } from 'commander';
import chalk from 'chalk';
import { getDb } from '@flusk/resources';

export const alertsMuteCommand = new Command('alerts-mute')
  .description('Enable or disable an alert channel')
  .requiredOption('--name <name>', 'Channel name')
  .option('--unmute', 'Re-enable the channel')
  .action(async (opts) => {
    const db = getDb();
    const { AlertChannelRepository } = await import('@flusk/resources');
    const channels = AlertChannelRepository.listAlertChannels(db);
    const channel = channels.find((c) => c.name === opts.name);

    if (!channel) {
      console.error(chalk.red(`Channel "${opts.name}" not found`));
      process.exit(1);
    }

    const enabled = Boolean(opts.unmute);
    AlertChannelRepository.updateAlertChannel(db, channel.id, { enabled });

    const verb = enabled ? 'unmuted' : 'muted';
    console.log(chalk.green(`✅ Channel "${channel.name}" ${verb}`));
  });
